INSERT INTO lore_nodes (id, name_th, name_en, lat, lng, radius_m, lore_pts, content_type, content_th, content_en, chain_id, chain_part, district_id, review_status)
VALUES
('lore-rangsit-canal', 'คลองรังสิตประยูรศักดิ์', 'Rangsit Canal', 14.0680, 100.6040, 100, 25, 'text',
 'คลองรังสิตประยูรศักดิ์เริ่มขุดเมื่อ พ.ศ. 2433 ในรัชสมัยพระบาทสมเด็จพระจุลจอมเกล้าเจ้าอยู่หัว ดำเนินการโดยบริษัท ขุดคลองแลคูนาสยาม จำกัด นับเป็นคลองสายหลักของโครงการพัฒนาที่ดินขนาดใหญ่โครงการแรกของประเทศไทย เชื่อมแม่น้ำเจ้าพระยากับแม่น้ำนครนายก เปิดพื้นที่รกร้างระหว่างสองแม่น้ำให้กลายเป็นที่ดินทำกินได้กว่าล้านไร่',
 'Rangsit Canal (Khlong Rangsit Prayurasakdi) began excavation in 1890 under King Chulalongkorn (Rama V), carried out by the Siam Canal, Land, and Irrigation Company. It formed the main artery of Thailand''s first large-scale land development project, linking the Chao Phraya and Nakhon Nayok rivers and opening over a million rai of previously unused land between them for cultivation.',
 NULL, NULL, 'rangsit', 'pending'),
('lore-rangsit-agriculture', 'เกษตรกรรมแห่งรังสิต', 'Rangsit Agricultural Development', 14.0740, 100.6090, 100, 25, 'text',
 'การขุดคลองรังสิตทำให้เกิดโครงข่ายคลองซอยกว่า 100 สาย ระบายน้ำและชลประทานพื้นที่ราบลุ่มภาคกลางตอนล่าง เปลี่ยนทุ่งร้างให้กลายเป็นแหล่งปลูกข้าวที่สำคัญที่สุดแห่งหนึ่งของสยาม ดึงดูดชาวนาจากทั่วประเทศให้อพยพเข้ามาจับจองที่ดิน วางรากฐานให้รังสิตกลายเป็นศูนย์กลางเกษตรกรรมของจังหวัดปทุมธานีมาจนถึงปัจจุบัน',
 'The Rangsit Canal project spawned a network of over 100 branch canals, draining and irrigating the lower central plain and turning previously idle fields into one of Siam''s most important rice-growing regions. It drew farmers from across the country to claim land, laying the foundation for Rangsit''s continued role as the agricultural center of Pathum Thani province.',
 NULL, NULL, 'rangsit', 'pending'),
('lore-rangsit-name-origin', 'ที่มาของชื่อ "รังสิต"', 'The Name "Rangsit"', 14.0700, 100.6110, 100, 25, 'text',
 'ชื่อ "รังสิต" มาจากพระนามของพระเจ้าลูกยาเธอ พระองค์เจ้ารังสิตประยูรศักดิ์ พระราชโอรสองค์ที่ 58 ในพระบาทสมเด็จพระจุลจอมเกล้าเจ้าอยู่หัว ประสูติแต่เจ้าจอมมารดาหม่อมราชวงศ์เนื่อง สนิทวงศ์ คลองและพื้นที่โดยรอบจึงได้รับพระราชทานนามตามพระนามของพระองค์ ภายหลังทรงเลื่อนกรมขึ้นเป็นสมเด็จพระเจ้าบรมวงศ์เธอ กรมพระยาชัยนาทนเรนทร ทรงมีบทบาทสำคัญด้านการแพทย์และสาธารณสุขของประเทศในเวลาต่อมา',
 'The name "Rangsit" derives from Prince Rangsit Prayurasakdi, the 58th son of King Chulalongkorn (Rama V), born to Chao Chom Manda M.R. Nueang Sanitwong. The canal and surrounding area were named in his honor. He was later elevated in rank to Prince Chainat Narenthorn (กรมพระยาชัยนาทนเรนทร) — the same "Prince of Chainat" — and went on to play a major role in Thailand''s medicine and public health institutions.',
 NULL, NULL, 'rangsit', 'pending')
ON CONFLICT (id) DO NOTHING;
